solution.code:
def climb_stairs(n, memo={1: 1, 2: 2}):
    if n in memo: return memo[n]
    memo[n] = climb_stairs(n - 1, memo) + climb_stairs(n - 2, memo)
    return memo[n]

if __name__ == "__main__":
    print(f"Ways: {climb_stairs(5)}")
